            "worker-2",
            "claude-sonnet",
            500,
            250,
            0.02,
        );
        metrics.record_call(&call2);

        assert_eq!(metrics.total_calls, 2);
        assert!((metrics.total_cost - 0.07).abs() < 0.001);
        assert_eq!(metrics.total_tokens(), 2250);
        assert!((metrics.avg_cost_per_call() - 0.035).abs() < 0.0001);

        // Clear
