    fn test_realtime_metrics() {
        let mut metrics = RealtimeMetrics::new();
        assert!(!metrics.has_data());
        assert_eq!(metrics.total_calls, 0);

        // Record a call
        let call = ApiCall::new(
            Utc::now(),
            "worker-1",
            "claude-opus",
