/// Handle debounced file system events.
fn handle_debounced_events(
    result: DebounceEventResult,
    status_dir: &Path,
    event_tx: &Sender<StatusEvent>,
) {
    match result {
        Ok(events) => {
            for event in events {
                Self::process_event(event, status_dir, event_tx);
            }
        }
        Err(errors) => {
            for error in errors {
                error!(error = %error, "File watcher error");
            }
        }
    }
}

